function adjustFontSizeToFit(t,n,s={}){const e=document.getElementById(t);if(!e)return;const{startRem:o=.8,minPx:l=8,stepPx:i=1}=s,c=Math.round(16*n);let d=Math.round(16*o);d<l&&(d=l);let r=null;const apply=t=>{null!=r&&e.classList.remove(`font-size-px-${r}`),r=t,e.classList.add(`font-size-px-${t}`)};for(apply(d);e.scrollWidth>c&&d>l;)d-=i,apply(d)}